import { useEffect, useState } from "react";
import { Trophy } from "lucide-react";

interface DemoProps {}

const loadingTexts = [
  "正在加载活动资源...",
  "加载首页素材...",
  "加载奖品数据...",
  "准备就绪！",
];

export default function Demo(_props: DemoProps) {
  const [progress, setProgress] = useState(0);
  const [textIndex, setTextIndex] = useState(0);
  const [showReady, setShowReady] = useState(false);

  useEffect(() => {
    if (progress >= 100) {
      setShowReady(true);
      return;
    }

    const timer = setInterval(() => {
      setProgress((prev) => {
        const increment = Math.random() * 8 + 2;
        const next = Math.min(prev + increment, 100);
        return next;
      });
    }, 400);

    return () => clearInterval(timer);
  }, [progress]);

  useEffect(() => {
    const idx = Math.min(Math.floor(progress / 30), loadingTexts.length - 1);
    setTextIndex(idx);
  }, [progress]);

  return (
    <div className="fixed inset-0 bg-gradient-to-br from-[#FF6B35] via-orange-500 to-orange-400 flex flex-col items-center justify-center">
      {/* Logo Area */}
      <div className="relative mb-10">
        {/* Soccer ball logo */}
        <div
          className={`w-28 h-28 bg-white/20 backdrop-blur-sm rounded-full flex items-center justify-center shadow-2xl border-4 border-white/30 ${
            showReady ? "" : "animate-spin"
          }`}
          style={showReady ? {} : { animationDuration: "3s" }}
        >
          <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center relative overflow-hidden">
            {/* Simple soccer ball pattern */}
            <span className="text-5xl">⚽</span>
            <div className="absolute inset-0 flex items-center justify-center">
              <div className="w-8 h-8 rounded-full border-4 border-gray-800/10 absolute top-1"></div>
              <div className="w-6 h-6 rounded-full border-4 border-gray-800/10 absolute bottom-2 left-3"></div>
              <div className="w-6 h-6 rounded-full border-4 border-gray-800/10 absolute bottom-2 right-3"></div>
            </div>
          </div>
        </div>
        {/* Cute face decoration */}
        <div className="absolute -bottom-2 -right-2 bg-white rounded-full w-10 h-10 flex items-center justify-center shadow-lg animate-bounce">
          <span className="text-lg">😊</span>
        </div>
        {/* Brand text */}
        <div className="text-center mt-4">
          <h1 className="text-white text-3xl font-bold drop-shadow-lg">
            叫叫足球嘉年华
          </h1>
        </div>
      </div>

      {/* Loading Bar */}
      <div className="w-64 mb-6">
        <div className="h-3 bg-white/20 rounded-full overflow-hidden backdrop-blur-sm shadow-inner">
          <div
            className={`h-full rounded-full transition-all duration-300 ease-out ${
              showReady
                ? "bg-green-400 shadow-lg shadow-green-400/50"
                : "bg-white shadow-lg shadow-white/50"
            }`}
            style={{
              width: `${progress}%`,
              transition: "width 0.4s ease-out",
            }}
          />
        </div>
      </div>

      {/* Loading Text */}
      <p
        className={`text-white text-lg font-medium transition-all duration-500 ${
          showReady ? "scale-110" : ""
        }`}
      >
        {showReady ? (
          <span className="inline-flex items-center gap-2">
            <Trophy className="w-6 h-6 text-yellow-300" />
            准备就绪！
            <Trophy className="w-6 h-6 text-yellow-300" />
          </span>
        ) : (
          loadingTexts[textIndex]
        )}
      </p>

      {/* Decorative elements */}
      <div className="absolute top-20 left-10 text-white/10 text-6xl animate-pulse">⚽</div>
      <div className="absolute bottom-32 right-10 text-white/10 text-5xl animate-pulse" style={{ animationDelay: "1s" }}>🌟</div>
      <div className="absolute top-40 right-20 text-white/10 text-4xl animate-pulse" style={{ animationDelay: "0.5s" }
