import { useState, useEffect } from "react";
import { AlertTriangle, X, ArrowRight } from "lucide-react";

interface DemoProps {}

export default function Demo(_props: DemoProps) {
  const [showModal, setShowModal] = useState(false);
  const [isUnderage, setIsUnderage] = useState(false);
  const [showUnderagePage, setShowUnderagePage] = useState(false);

  useEffect(() => {
    setShowModal(true);
  }, []);

  const handleAdult = () => {
    setIsUnderage(false);
    setShowModal(false);
  };

  const handleUnderage = () => {
    setIsUnderage(true);
    setShowUnderagePage(true);
    setShowModal(false);
  };

  const handleBackToActivities = () => {
    setShowUnderagePage(false);
    setShowModal(false);
  };

  // Underage result page
  if (showUnderagePage) {
    return (
      <div className="fixed inset-0 bg-gradient-to-br from-gray-100 to-gray-200 flex items-center justify-center p-6">
        <div className="bg-white rounded-3xl shadow-2xl p-8 max-w-sm w-full text-center animate-[fadeIn_0.4s_ease-out]">
          <div className="w-20 h-20 mx-auto bg-gray-100 rounded-full flex items-center justify-center mb-5">
            <AlertTriangle className="w-10 h-10 text-gray-400" />
          </div>
          <h2 className="text-xl font-bold text-gray-800 mb-3">
            抱歉，您暂无法参与本次活动
          </h2>
          <p className="text-gray-500 text-sm leading-relaxed mb-6">
            感谢您的关注，我们准备了更多适合你的精彩内容！
          </p>
          <button
            onClick={handleBackToActivities}
            className="w-full bg-[#FF6B35] text-white py-3 rounded-xl font-medium flex items-center justify-center gap-2 hover:bg-orange-600 transition-colors shadow-lg shadow-orange-200"
          >
            去看看其他活动
            <ArrowRight className="w-4 h-4" />
          </button>
        </div>
      </div>
    );
  }

  return (
