interface TimeLeft {
  days: number;
  hours: number;
  minutes: number;
  seconds: number;
}

const prizes = [
  { emoji: "⚽", name: "签名足球", desc: "球星亲笔签名足球" },
  { emoji: "🏅", name: "限定徽章", desc: "嘉年华限定纪念徽章" },
  { emoji: "🃏", name: "球星卡", desc: "限量版珍藏球星卡" },
  { emoji: "🎽", name: "球衣", desc: "国家队正版球衣" },
];

export default function Demo(_props: DemoProps) {
  const [timeLeft, setTimeLeft] = useState<TimeLeft>({
    days: 3,
    hours: 12,
    minutes: 30,
    seconds: 0,
  });

  useEffect(() => {
    const totalSeconds =
      timeLeft.days * 86400 +
      timeLeft.hours * 3600 +
      timeLeft.minutes * 60 +
      timeLeft.seconds;

    if (totalSeconds <= 0) return;

    const timer = setInterval(() => {
      setTimeLeft((prev) => {
        let total =
          prev.days * 86400 + prev.hours * 3600 + prev.minutes * 60 + prev.seconds - 1;
        if (total <= 0) {
          clearInterval(timer);
          return { days: 0, hours: 0, minutes: 0, seconds: 0 };
        }
        const d = Math.floor(total / 86400);
        total %= 86400;
        const h = Math.floor(total / 3600);
        total %= 3600;
        const m = Math.floor(total / 60);
        const s = total % 60;
        return { days: d, hours: h, minutes: m, seconds: s };
      });
    }, 1000);

    return () => clearInterval(timer);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const pad = (n: number) => String(n).padStart(2, "0");

  return (
    <div className="min-h-screen bg-white flex flex-col max-w-md mx-auto">
