            ⚽ 叫叫足球嘉年华
          </span>
        </div>
        <div className="flex items-center gap-4">
          <Share2 className="w-5 h-5 text-gray-600" />
          <Info className="w-5 h-5 text-gray-600" />
        </div>
      </header>

      {/* 滚动内容区 */}
      <div className="flex-1 overflow-y-auto">
        {/* 主视觉头图 */}
        <div
          className="relative px-6 py-10 text-center text-white overflow-hidden"
          style={{
            background: "linear-gradient(135deg, #FF6B35 0%, #1A365D 100%)",
          }}
        >
          {/* 装饰星星 */}
          <span className="absolute top-4 left-8 text-2xl opacity-60">⭐</span>
          <span className="absolute top-8 right-12 text-xl opacity-40">🌟</span>
          <span className="absolute bottom-12 left-6 text-lg opacity-50">✨</span>
          <span className="absolute bottom-6 right-8 text-2xl opacity-40">⭐</span>

          <div className="text-6xl mb-2">⚽</div>
          <h1 className="text-xl font-bold mb-3">叫叫足球嘉年华</h1>
          <p className="text-sm opacity-90 mb-4">与全球小球迷一起狂欢</p>

          {/* 倒计时 */}
          <div className="inline-flex items-center gap-2 bg-white/20 backdrop-blur-sm rounded-full px-5 py-2">
            <span className="text-sm">距活动开始</span>
            <span className="text-lg font-bold tabular-nums">{pad(timeLeft.days)}</span>
